# Decorator for caching function results
def cached(prefix, ttl=None):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            cache_key = cache_manager.generate_key(prefix, *args, **kwargs)
            cached_result = cache_manager.get(cache_key)
            if cached_result is not None:
                if isinstance(cached_result, dict):
                    cached_result['_cache'] = 'HIT'
                return cached_result
            result = func(*args, **kwargs)
            if result is not None:
                cache_manager.set(cache_key, result, ttl=ttl or app.config['DEFAULT_CACHE_TTL'])
            if isinstance(result, dict):
                result['_cache'] = 'MISS'
            return result
        return wrapper
    return decorator


# Decorator for caching route responses
def cache_route(ttl=None):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            cache_key = f"route:{request.path}:{request.query_string.decode('utf-8')}"
            cache_key_hash = hashlib.md5(cache_key.encode()).hexdigest()
            final_key = f"route:{cache_key_hash}"

            cached_response = cache_manager.get(final_key)
            if cached_response is not None:
                cached_response['_cache'] = 'HIT'
                cached_response['_cache_key'] = final_key
                return jsonify(cached_response)

            result = func(*args, **kwargs)

            if isinstance(result, dict):
                cache_manager.set(final_key, result, ttl=ttl or app.config['API_CACHE_TTL'])
                result['_cache'] = 'MISS'
                result['_cache_key'] = final_key
                return jsonify(result)
            return result
        return wrapper
    return decorator


